	m.HandleFunc("GET "+options.BaseURL+"/matrixExplodeObject/{id}", wrapper.GetMatrixExplodeObject)
	m.HandleFunc("GET "+options.BaseURL+"/matrixExplodePrimitive/{id}", wrapper.GetMatrixExplodePrimitive)
	m.HandleFunc("GET "+options.BaseURL+"/matrixNoExplodeArray/{id}", wrapper.GetMatrixNoExplodeArray)
	m.HandleFunc("GET "+options.BaseURL+"/matrixNoExplodeObject/{id}", wrapper.GetMatrixNoExplodeObject)
	m.HandleFunc("GET "+options.BaseURL+"/matrixPrimitive/{id}", wrapper.GetMatrixPrimitive)
